import{_ as e,o as r,c as d,a2 as o}from"./chunks/framework.BflysNKA.js";const u=JSON.parse('{"title":"Windows 接入 Cherry Studio","description":"","frontmatter":{},"headers":[],"relativePath":"beginner/windows-cherry-studio.md","filePath":"beginner/windows-cherry-studio.md","lastUpdated":1780486201000}'),a={name:"beginner/windows-cherry-studio.md"};function n(i,t,s,h,l,c){return r(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="windows-接入-cherry-studio" tabindex="-1">Windows 接入 Cherry Studio <a class="header-anchor" href="#windows-接入-cherry-studio" aria-label="Permalink to &quot;Windows 接入 Cherry Studio&quot;">​</a></h1><p>Cherry Studio 是图形界面聊天客户端，<strong>不需要安装 Git、Node.js 或任何命令行工具</strong>。适合第一次验证接口是否可用。</p><div class="info custom-block"><p class="custom-block-title">前置条件</p><p>开始之前，确保你已经完成：</p><ol><li>✅ 小蓝中转站 账号已注册并充值</li><li>✅ 已创建 API 密钥（以 <code>sk-</code> 开头的字符串）</li><li>✅ 已从模型广场复制模型名</li></ol><p>还没做？先回 <a href="/beginner/windows">Windows 快速接入</a> 的第一阶段。</p></div><h2 id="第-1-步-下载安装" tabindex="-1">第 1 步：下载安装 <a class="header-anchor" href="#第-1-步-下载安装" aria-label="Permalink to &quot;第 1 步：下载安装&quot;">​</a></h2><p>从 <a href="https://docs.cherry-ai.com/cherry-studio/download" target="_blank" rel="noreferrer">Cherry Studio 官网下载页</a> 下载 Windows 版本。</p><p>下载后双击安装包，按提示完成安装。安装完成后启动 Cherry Studio。</p><h2 id="第-2-步-添加-xiaolan-服务商" tabindex="-1">第 2 步：添加 小蓝中转站 服务商 <a class="header-anchor" href="#第-2-步-添加-xiaolan-服务商" aria-label="Permalink to &quot;第 2 步：添加 小蓝中转站 服务商&quot;">​</a></h2><p>打开 Cherry Studio 后，进入 <strong>设置</strong>（左下角齿轮图标）→ <strong>服务商</strong>，点击添加新的服务商。</p><p>按以下信息填写：</p><table tabindex="0"><thead><tr><th>字段</th><th>填什么</th><th>注意</th></tr></thead><tbody><tr><td><strong>服务商类型</strong></td><td><code>OpenAI 兼容</code></td><td>不要选其他类型</td></tr><tr><td><strong>API 地址</strong></td><td><code>https://xiaolan1.cn</code></td><td><strong>不要加 <code>/v1</code></strong>，Cherry Studio 会自己拼接</td></tr><tr><td><strong>API Key</strong></td><td><code>sk-你的专属Key</code></td><td>从控制台复制的完整 Key</td></tr></tbody></table><p>填好后点 <strong>保存</strong>。</p><h2 id="第-3-步-验证连接" tabindex="-1">第 3 步：验证连接 <a class="header-anchor" href="#第-3-步-验证连接" aria-label="Permalink to &quot;第 3 步：验证连接&quot;">​</a></h2><p>保存后点 <strong>Check</strong>（或「检查」按钮），验证连接是否正常。</p><p>如果 Check 通过，点 <strong>拉取模型列表</strong>，Cherry Studio 会自动获取可用模型。</p><h2 id="第-4-步-发送测试消息" tabindex="-1">第 4 步：发送测试消息 <a class="header-anchor" href="#第-4-步-发送测试消息" aria-label="Permalink to &quot;第 4 步：发送测试消息&quot;">​</a></h2><p>新建一个对话，在模型下拉框中选一个刚拉下来的模型，发送「你好」。</p><p>能收到回复，说明配置成功。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>可能原因</th><th>怎么处理</th></tr></thead><tbody><tr><td>Check 失败</td><td>API 地址或 Key 错误</td><td>确认地址是 <code>https://xiaolan1.cn</code>（不带 <code>/v1</code>），Key 以 <code>sk-</code> 开头</td></tr><tr><td>模型列表为空</td><td>Key 没有模型权限</td><td>回控制台检查 Key 的分组和模型权限</td></tr><tr><td>模型列表有但发消息报错</td><td>模型选错或余额不足</td><td>确认选的模型在列表中，检查余额</td></tr><tr><td>下载或安装失败</td><td>网络问题</td><td>直接从官网下载安装包，不通过应用商店</td></tr></tbody></table><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>Cherry Studio 配置成功后，说明你的 小蓝中转站 账号、Key 和余额都没问题。如果想继续接入命令行工具：</p><ul><li>→ <a href="/beginner/windows-claude-code">Claude Code 接入</a>（需要先做<a href="/beginner/windows-env">环境准备</a>）</li><li>→ <a href="/beginner/windows-codex">Codex 接入</a>（需要先做<a href="/beginner/windows-env">环境准备</a>）</li></ul>',22)])])}const b=e(a,[["render",n]]);export{u as __pageData,b as default};
